                node
                    .lastChildLeafOrSelf()
                    .nextLeaf()
                    .safeAs<LeafPsiElement>()
                    ?.let {
                        if (it.elementType == WHITE_SPACE) {
                            it.replaceWithText(getNewlineWithIndent(node.treeParent))
                        } else {
