    private fun ASTNode.isOnSameLineAsNextAnnotationEntryOrAnnotatedConstruct() =
        if (isFollowedByOtherAnnotationEntry()) {
            isOnSameLineAsNextAnnotationEntry()
        } else {
            isOnSameLineAsAnnotatedConstruct()
        }

    private fun ASTNode.isPartOfPrimaryConstructor(): Boolean =
        treeParent?.elementType == MODIFIER_LIST &&
            treeParent?.treeParent?.elementType == PRIMARY_CONSTRUCTOR

    private fun ASTNode.isOnSameLineAsClassIdentifier(): Boolean {
